  private val uploadsDir: Path = environment.rootPath.toPath.resolve("uploads")

  /**
   * Serves a file specified by the filename from the `uploadsDir`.
   * Supports subdirectories within the filename parameter (e.g., "images/photo.jpg").
   *
   * @param filename The name of the file, potentially including subdirectory paths.
