  def serveUserFile(filename: String) = Action { implicit request =>
    // 1. Construct the absolute path to the requested file.
    //    `resolve` appends the filename safely, and `normalize` removes redundant ".." and "."
    val requestedPath = uploadsDir.resolve(filename).normalize()

    // 2. Security Check: Prevent path traversal attacks.
